// Filter: Contacté + no reply detected + 24h-48h old (relance window)
const rows = $input.first().json.rows || [];
const now  = Date.now();

const targets = rows.filter(r => {
  const status = (r['Statut'] || '').toLowerCase();
  // Only follow up leads marked Contacté but not yet confirmed/cancelled
  if (!['contacté', 'contacte'].includes(status)) return false;
  const created = new Date(r['Date']);
  if (isNaN(created)) return false;
  const ageH = (now - created.getTime()) / 3600000;
  // Relance window: 24h to 72h after first contact
  return ageH >= 24 && ageH < 72 && !String(r['Notes']||'').includes('Relance envoyée');
});

return targets.map(r => ({
  json: {
    _row:        r._row,
    name:        r['Nom']        || '',
    phone:       r['Téléphone']  || '',
    carType:     r['Voiture demandée'] || '',
    dates:       r['Dates location']   || '',
    firstName:   String(r['Nom']||'').split(' ')[0],
    phoneNorm:   (() => {
      const p = String(r['Téléphone']||'').replace(/\D/g,'');
      if (p.startsWith('0') && p.length===10) return '212'+p.slice(1);
      if (!p.startsWith('212') && p.length===9) return '212'+p;
      return p;
    })()
  }
}));

